/**
 *
 * @param context
 * @param layout
 * @param nodeOptions
 * @param linkOptions
 * @param nodeFillColor
 * @param linkFillColor
 */
import { drawSankeyNode } from './sankey-node';
import { sankeyLinkBezier, sankeyLinkLinear } from './sankey-link';
import { defined } from '../utils/zcutils';
import { effects } from '../effects/zceffects';
import { sankeyCanvasCircularLink } from './sankey-canvas-circular-link';
import { drawSankeyExitLink } from './sankey-exit-link';
import { rgba_canvas } from '../utils/colorutils';

export function drawSankeyCanvas(context, layout, nodeOptions, linkOptions, nodeFillColor, linkFillColor, imagePallet, chartInstance) {
    let { nodes, links } = layout,
        nodeStrokeWidth = nodeOptions.strokeWidth,
        linkStrokeWidth = linkOptions.strokeWidth,
        isSelectionCanvas = context.canvas.className == 'selection-canvas' ? true : false,
        isSelectionContainer = !(chartInstance.container.select('.selection-canvas').empty());

    context.save();
    context.translate(nodeStrokeWidth, nodeStrokeWidth);

    if (defined(linkOptions.blendMode)) {
        context.globalCompositeOperation = linkOptions.blendMode;
    }

    /**
     *
     * @param link
     * @param fillStyle
     */
    const renderLink = (link, fillStyle, layout) => {
        context.save();

        context.fillStyle = fillStyle;
        context.strokeStyle = linkOptions.strokeColor;
        context.lineWidth = linkStrokeWidth;
        context.beginPath();
        if (link.circular) {
            sankeyCanvasCircularLink(context, link);
        } else if (link.exit) {
            drawSankeyExitLink(context, link, linkOptions, 0.5, layout);
        } else {
            (linkOptions.curve === 'linear' ? sankeyLinkLinear : sankeyLinkBezier)(context, link, linkOptions, 0.5);
        }

        // #ZC2592
        context.translate(link.source.x0, 0);
        context.fill();

        if (linkStrokeWidth) {
            context.stroke();
        }

        context.restore();
    };
    
    if(isSelectionContainer){
        var selectionArray = chartInstance.cache.clickSelectionData;

        if(isSelectionContainer && defined(selectionArray[0])){
            chartInstance.container.select('.zc-canvas').style("visibility", "hidden");
        }
        else{
            chartInstance.container.select('.selection-canvas').style("visibility", "hidden");
            chartInstance.container.select('.zc-canvas').style("visibility", "visible");
        }
    }
    

    links.forEach(link => {
        if (isCanvasPattern(linkOptions.fillColor)) {
            renderLink(link, linkOptions.fillColor, layout);
        } else if (defined(imagePallet)) {
            let params = { context: context, name: imagePallet[link.source.index] };
            effects.canvas_patterns.imageFill(params, (context, pattern) => renderLink(link, pattern, layout));
        } 
        else if(isSelectionCanvas){
            if(!defined(link.point.clickSelection) || !(link.point.clickSelection) && defined(selectionArray[0])){
                renderLink(link, rgba_canvas(linkOptions.fillColor, linkOptions.fillOpacity), layout);
            }
            else{
                renderLink(link, rgba_canvas(linkFillColor(link.point), linkOptions.fillOpacity), layout);
            }
        }else {
            renderLink(link, linkFillColor(link.point), layout);
        }
    });

    const renderNode = (node, fillStyle) => {
        context.save();
        context.fillStyle = fillStyle;
        context.lineWidth = nodeStrokeWidth;
        context.strokeStyle = nodeOptions.strokeColor;
        context.beginPath();
        node.color = fillStyle;
        drawSankeyNode(context, node, nodeOptions);
        context.fill();

        if (nodeStrokeWidth) {
            context.stroke();
        }
        context.restore();
    };

    nodes.forEach(node => {
        if (isCanvasPattern(nodeOptions.fillColor)) {
            renderNode(node, nodeOptions.fillColor);
        } else if (defined(imagePallet)) {
            let params = { context: context, name: imagePallet[node.index] };
            effects.canvas_patterns.imageFill(params, (context, pattern) => renderNode(node, pattern));
        } 
        else if(isSelectionCanvas && (!defined(node.point.clickSelection) || !(node.point.clickSelection) && defined(selectionArray[0]))){
            renderNode(node, nodeOptions.fillColor);
        }else {
            renderNode(node, nodeFillColor(node.point));
        }
    });

    context.restore();
}

/**
 *
 * @param fillStylgit e
 * @return {boolean}
 */
function isCanvasPattern(fillStyle) {
    return fillStyle instanceof CanvasPattern;
}
